const customers = $('Fetch New Customers').all().map(i => i.json);
const sentHistory = $('Fetch Sent History').all().map(i => i.json);

const alreadySent = new Set();
for (const s of sentHistory) {
  if (s.contact_email && s.email_type) {
    alreadySent.add(s.contact_email + '|' + s.email_type);
  }
}

// ── HTML email builder ──
const FONT = "-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif";
const GREEN = '#2D5A27';
const GOLD = '#C5A55A';

function checkItem(text) {
  return '<tr><td style="padding:0 32px 16px;"><table role="presentation" cellspacing="0" cellpadding="0" border="0" width="100%"><tr><td width="44" valign="top" style="padding-right:12px;"><table role="presentation" cellspacing="0" cellpadding="0" border="0"><tr><td align="center" valign="middle" width="36" height="36" style="background-color:#eaf5e8; border-radius:50%;"><span style="font-size:18px; line-height:36px; color:' + GREEN + ';">&#10003;</span></td></tr></table></td><td valign="middle" style="font-family:' + FONT + '; font-size:15px; color:#1a1a1a; line-height:1.5;">' + text + '</td></tr></table></td></tr>';
}

function reviewBlock(reviewText, reviewerName) {
  return '<tr><td style="padding:0 32px 32px;"><table role="presentation" cellspacing="0" cellpadding="0" border="0" width="100%" style="background-color:#f9f9f9; border-radius:8px;"><tr><td align="center" style="padding:28px 28px 8px;"><span style="font-size:24px; color:' + GOLD + '; letter-spacing:2px;">&#9733;&#9733;&#9733;&#9733;&#9733;</span></td></tr><tr><td align="center" style="padding:8px 28px;"><p style="margin:0; font-family:Georgia,\'Times New Roman\',Times,serif; font-size:15px; color:#333333; line-height:1.7; font-style:italic;">&ldquo;' + reviewText + '&rdquo;</p></td></tr><tr><td align="center" style="padding:12px 28px 4px;"><p style="margin:0; font-family:' + FONT + '; font-size:14px; color:#1a1a1a; font-weight:700; line-height:1.4;">&mdash; ' + reviewerName + '</p></td></tr><tr><td align="center" style="padding:0 28px 28px;"><p style="margin:0; font-family:' + FONT + '; font-size:12px; color:#888888; line-height:1.4; text-transform:uppercase; letter-spacing:0.5px;">Verified Google Review</p></td></tr></table></td></tr>';
}

function miniReviewBlock(reviews) {
  let rows = '';
  for (const r of reviews) {
    rows += '<tr><td style="padding:8px 28px; border-bottom:1px solid #eeeeee;"><p style="margin:0 0 4px; font-family:' + FONT + '; font-size:14px; color:#1a1a1a; font-weight:700;"><span style="color:' + GOLD + ';">&#9733;&#9733;&#9733;&#9733;&#9733;</span> ' + r.name + '</p><p style="margin:0; font-family:Georgia,\'Times New Roman\',Times,serif; font-size:14px; color:#555555; line-height:1.5; font-style:italic;">&ldquo;' + r.text + '&rdquo;</p></td></tr>';
  }
  return '<tr><td style="padding:0 32px 32px;"><table role="presentation" cellspacing="0" cellpadding="0" border="0" width="100%" style="background-color:#f9f9f9; border-radius:8px;"><tr><td align="center" style="padding:24px 28px 8px;"><p style="margin:0; font-family:' + FONT + '; font-size:13px; color:#555555; text-transform:uppercase; letter-spacing:1.5px; font-weight:700;">What Your Neighbors Are Saying</p></td></tr>' + rows + '<tr><td align="center" style="padding:12px 28px 24px;"><p style="margin:0; font-family:' + FONT + '; font-size:12px; color:#888888; text-transform:uppercase; letter-spacing:0.5px;">Verified Google Reviews</p></td></tr></table></td></tr>';
}

function ctaButton(text, url) {
  return '<tr><td style="padding:0 32px 32px;" align="center"><table role="presentation" cellspacing="0" cellpadding="0" border="0" style="width:100%;"><tr><td align="center" style="border-radius:6px; background-color:' + GREEN + ';"><a href="' + url + '" target="_blank" style="display:block; padding:16px 32px; font-family:' + FONT + '; font-size:16px; font-weight:700; color:#ffffff; text-decoration:none; border-radius:6px; background-color:' + GREEN + '; text-align:center;">' + text + '</a></td></tr></table></td></tr>';
}

