  return '<!DOCTYPE html><html xmlns="http://www.w3.org/1999/xhtml" lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0">' + style + '</head><body style="margin:0;padding:0;background-color:#f4f4f4;"><div style="display:none;font-size:1px;color:#f4f4f4;line-height:1px;max-height:0;max-width:0;opacity:0;overflow:hidden;">' + (opts.previewText || '') + '</div><table role="presentation" cellspacing="0" cellpadding="0" border="0" width="100%" style="background-color:#f4f4f4;"><tr><td align="center" valign="top" style="padding:20px 0;"><table role="presentation" cellspacing="0" cellpadding="0" border="0" width="600" class="email-container" style="margin:0 auto;max-width:600px;background-color:#ffffff;border-radius:8px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.06);">' + headerBar + banner + opts.bodyHtml + (opts.reviewHtml || '') + ctaButton(opts.ctaText, opts.ctaUrl) + trustBar + footer + '</table></td></tr></table></body></html>';
